function pingHost(ip, timeoutMs) {
  return new Promise((resolve) => {
    exec(`ping -n 1 -w ${timeoutMs} ${ip}`, (error, stdout) => {
      const ttlMatch = stdout.match(/TTL=(\d+)/i);
      if (ttlMatch) resolve({ ip, active: true, ttl: parseInt(ttlMatch[1], 10) });
      else resolve({ ip, active: false, ttl: null });
    });
  });
}

function getOSFromTTL(ttl) {
